const FINALIZATION_ID: &str = "durable-completion-finalization-0001";
const FINALIZATION_DIGEST: &str = "finalization-digest-ffffffffffffffffffff";
const REPORT_DIGEST: &str = "completion-report-digest-cccccccccccccccc";
const RECEIPT_DIGEST: &str = "consume-receipt-digest-rrrrrrrrrrrrrrrr";
const SINK_DIGEST: &str = "sink-decision-digest-ssssssssssssssssssss";
const REPORTER_DIGEST: &str = "reporter-decision-digest-eeeeeeeeeeeeeeee";
const PIPELINE_DIGEST: &str = "modeled-pipeline-decision-digest-pppppppp";
const CAND_DIGEST: &str = "candidate-digest-aaaaaaaaaaaaaaaaaaaaaaaa";
const PROPOSAL: &str = "proposal-0001";
const DECISION: &str = "decision-0001";
const CHAIN: &str = "qbind-devnet";
const GENESIS: &str = "genesis-hash-dddddddddddddddddddddddddddd";
const SEQUENCE: u64 = 7;

struct Ctx {
    env: ModeledGovernanceTrustMutationEnvironmentBinding,
    runtime: ModeledGovernanceTrustMutationRuntimeBinding,
    finalization: GovernanceModeledDurableCompletionFinalizationRecord,
    expectations: GovernanceModeledDurableCompletionFinalizationExpectations,
}

fn ctx(environment: TrustBundleEnvironment, vs: GovernanceExecutionRuntimeSurface, ms: GovernanceExecutionRuntimeSurface) -> Ctx {
    let env = ModeledGovernanceTrustMutationEnvironmentBinding { environment, chain_id: CHAIN.to_string(), genesis_hash: GENESIS.to_string() };
    let runtime = ModeledGovernanceTrustMutationRuntimeBinding { governance_surface: ms, mutation_surface: ModeledGovernanceTrustMutationSurface { validation_surface: vs, mutation_surface: ms }, authority_domain_sequence: SEQUENCE };
    let finalization = GovernanceModeledDurableCompletionFinalizationRecord {
        finalization_id: FINALIZATION_ID.to_string(), finalization_digest: FINALIZATION_DIGEST.to_string(), report_digest: REPORT_DIGEST.to_string(), receipt_digest: RECEIPT_DIGEST.to_string(), proposal_id: PROPOSAL.to_string(), decision_id: DECISION.to_string(), candidate_digest: CAND_DIGEST.to_string(), authority_domain_sequence: SEQUENCE, sink_decision_digest: SINK_DIGEST.to_string(), reporter_decision_digest: REPORTER_DIGEST.to_string(), pipeline_decision_digest: PIPELINE_DIGEST.to_string(),
    };
    let expectations = GovernanceModeledDurableCompletionFinalizationExpectations {
        expected_environment: environment, expected_chain_id: CHAIN.to_string(), expected_genesis_hash: GENESIS.to_string(), expected_governance_surface: ms, expected_validation_surface: vs, expected_mutation_surface: ms, expected_finalization_digest: FINALIZATION_DIGEST.to_string(), expected_report_digest: REPORT_DIGEST.to_string(), expected_receipt_digest: RECEIPT_DIGEST.to_string(), expected_proposal_id: PROPOSAL.to_string(), expected_decision_id: DECISION.to_string(), expected_candidate_digest: CAND_DIGEST.to_string(), expected_authority_domain_sequence: SEQUENCE, expected_sink_decision_digest: SINK_DIGEST.to_string(), expected_reporter_decision_digest: REPORTER_DIGEST.to_string(), expected_pipeline_decision_digest: PIPELINE_DIGEST.to_string(),
    };
    Ctx { env, runtime, finalization, expectations }
}

impl Ctx {
    fn input(&self, policy: GovernanceModeledDurableCompletionFinalizationPolicy, replay: DurableReplayObservation, pipeline: GovernanceModeledEndToEndPipelineOutcome, sink: GovernanceModeledDurableConsumeSinkOutcome, reporter: GovernanceModeledDurableConsumeCompletionReporterOutcome) -> GovernanceModeledDurableCompletionFinalizationInput {
        GovernanceModeledDurableCompletionFinalizationInput { policy, environment_binding: self.env.clone(), runtime_binding: self.runtime.clone(), replay_binding: replay, pipeline_binding: pipeline, sink_binding: sink, reporter_binding: reporter, finalization: self.finalization.clone() }
    }
    fn recorded(&self) -> GovernanceModeledDurableCompletionFinalizationInput {
        self.input(GovernanceModeledDurableCompletionFinalizationPolicy::wired(), DurableReplayObservation::MutationAuthorized, GovernanceModeledEndToEndPipelineOutcome::ModeledApplierAppliedAndDurableConsumeAuthorized, GovernanceModeledDurableConsumeSinkOutcome::ConsumeReceiptRecorded, GovernanceModeledDurableConsumeCompletionReporterOutcome::CompletionReportRecorded)
    }
}
fn devnet_ctx() -> Ctx { ctx(TrustBundleEnvironment::Devnet, GovernanceExecutionRuntimeSurface::ReloadApply, GovernanceExecutionRuntimeSurface::ReloadApply) }
fn testnet_ctx() -> Ctx { ctx(TrustBundleEnvironment::Testnet, GovernanceExecutionRuntimeSurface::ReloadApply, GovernanceExecutionRuntimeSurface::ReloadApply) }
fn devnet_finalizer() -> FixtureModeledDurableCompletionFinalizer { FixtureModeledDurableCompletionFinalizer::new(TrustBundleEnvironment::Devnet) }

fn write_file(path: &Path, contents: &str) { if let Some(parent) = path.parent() { fs::create_dir_all(parent).unwrap(); } let mut f = fs::File::create(path).unwrap(); f.write_all(contents.as_bytes()).unwrap(); }

struct Table { name: &'static str, rows: String, expected: String, actual: String, pass: u64, fail: u64 }
impl Table {
    fn new(name: &'static str) -> Self { Self { name, rows: String::new(), expected: String::new(), actual: String::new(), pass: 0, fail: 0 } }
    fn check(&mut self, id: &str, expected: &str, actual: &str) { let ok = expected == actual; self.pass += ok as u64; self.fail += (!ok) as u64; self.rows.push_str(&format!("{id}\t{}\texpected={expected}\tactual={actual}\n", if ok {"PASS"} else {"FAIL"})); self.expected.push_str(&format!("{id}\t{expected}\n")); self.actual.push_str(&format!("{id}\t{actual}\n")); }
    fn assert_true(&mut self, id: &str, ok: bool) { self.check(id, "true", if ok {"true"} else {"false"}); }
    fn check_outcome(&mut self, id: &str, expected: &str, o: &GovernanceModeledDurableCompletionFinalizationOutcome) { self.check(id, expected, o.tag()); }
    fn finish(self, out: &Path) -> (u64, u64) { let dir = out.join("tables").join(self.name); write_file(&dir.join("manifest.txt"), &self.rows); write_file(&dir.join("expected.txt"), &self.expected); write_file(&dir.join("actual.txt"), &self.actual); (self.pass, self.fail) }
}

fn drive(input: &GovernanceModeledDurableCompletionFinalizationInput, expectations: &GovernanceModeledDurableCompletionFinalizationExpectations, finalizer: &mut FixtureModeledDurableCompletionFinalizer, ledger: &mut ModeledDurableCompletionFinalizationLedger) -> GovernanceModeledDurableCompletionFinalizationOutcome { evaluate_modeled_durable_completion_finalization_projection(input, expectations, finalizer, ledger) }

fn run_accepted_table(out: &Path) -> (u64, u64) {
    use DurableReplayObservation as R; use GovernanceModeledDurableCompletionFinalizationPolicy as P; use GovernanceModeledEndToEndPipelineOutcome as Pipe; use GovernanceModeledDurableConsumeSinkOutcome as Sink; use GovernanceModeledDurableConsumeCompletionReporterOutcome as Report;
    let mut t = Table::new("accepted");
    for (id, policy) in [("A1.finalizer-disabled", P::finalization_disabled()), ("A2.reporter-disabled", P::reporter_disabled()), ("A3.sink-disabled", P::sink_disabled()), ("A4.pipeline-disabled", P::pipeline_disabled()), ("A5.evaluator-disabled", P::evaluator_disabled())] {
        let c = devnet_ctx(); let input = c.input(policy, R::MutationAuthorized, Pipe::ModeledApplierAppliedAndDurableConsumeAuthorized, Sink::ConsumeReceiptRecorded, Report::CompletionReportRecorded); let mut ledger = ModeledDurableCompletionFinalizationLedger::new(); let mut finalizer = devnet_finalizer(); let o = drive(&input, &c.expectations, &mut finalizer, &mut ledger); t.check_outcome(&format!("{id}.outcome"), "legacy-bypass-no-finalization", &o); t.assert_true(&format!("{id}.no-invocation"), finalizer.invocations()==0); t.assert_true(&format!("{id}.ledger-empty"), ledger.is_empty());
    }
    for (id, c, env, kind) in [("A6.devnet", devnet_ctx(), TrustBundleEnvironment::Devnet, "fixture-devnet"), ("A7.testnet", testnet_ctx(), TrustBundleEnvironment::Testnet, "fixture-testnet")] {
        let mut ledger = ModeledDurableCompletionFinalizationLedger::new(); let mut finalizer = FixtureModeledDurableCompletionFinalizer::new(env); let o = drive(&c.recorded(), &c.expectations, &mut finalizer, &mut ledger); t.check_outcome(&format!("{id}.outcome"), "durable-completion-finalized", &o); t.assert_true(&format!("{id}.authorizes"), o.authorizes_modeled_durable_completion()); t.assert_true(&format!("{id}.projects"), o.projects_to_durable_completion()); t.assert_true(&format!("{id}.ledger-one"), ledger.len()==1); t.check(&format!("{id}.kind"), kind, finalizer.kind().tag());
    }
    for action in ["add-root", "retire-root", "revoke-root", "emergency-revoke-root", "noop"] { let c=devnet_ctx(); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut finalizer=devnet_finalizer(); let o=drive(&c.recorded(), &c.expectations, &mut finalizer, &mut ledger); t.check_outcome(&format!("A8.{action}.outcome"), "durable-completion-finalized", &o); t.assert_true(&format!("A8.{action}.ledger-one"), ledger.len()==1); }
    { let c=devnet_ctx(); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut finalizer=devnet_finalizer(); let first=drive(&c.recorded(), &c.expectations, &mut finalizer, &mut ledger); let second=drive(&c.recorded(), &c.expectations, &mut finalizer, &mut ledger); t.check_outcome("A9.first", "durable-completion-finalized", &first); t.check_outcome("A9.duplicate", "durable-completion-duplicate-idempotent", &second); t.assert_true("A9.ledger-one", ledger.len()==1); }
    { let c=devnet_ctx(); let dup_input = c.input(P::wired(), R::MutationAuthorized, Pipe::ModeledApplierAppliedAndDurableConsumeAuthorized, Sink::ConsumeReceiptRecorded, Report::CompletionReportDuplicateIdempotent); let mut empty=ModeledDurableCompletionFinalizationLedger::new(); let mut finalizer=devnet_finalizer(); let o=drive(&dup_input, &c.expectations, &mut finalizer, &mut empty); t.check_outcome("A10.duplicate-empty", "durable-completion-rejected-before-record", &o); t.assert_true("A10.empty", empty.is_empty()); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f2=devnet_finalizer(); let _=drive(&c.recorded(), &c.expectations, &mut f2, &mut ledger); let o2=drive(&dup_input, &c.expectations, &mut f2, &mut ledger); t.check_outcome("A10.duplicate-matches", "durable-completion-duplicate-idempotent", &o2); }
    { let c=devnet_ctx(); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=ProductionModeledDurableCompletionFinalizer::default(); let o=evaluate_modeled_durable_completion_finalization_projection(&c.recorded(), &c.expectations, &mut f, &mut ledger); t.check_outcome("A11.production", "production-finalizer-unavailable-no-finalization", &o); t.assert_true("A11.no-record", ledger.is_empty()); t.check("A11.kind", "production-unavailable", f.kind().tag()); }
    { let c=ctx(TrustBundleEnvironment::Mainnet, GovernanceExecutionRuntimeSurface::ReloadApply, GovernanceExecutionRuntimeSurface::ReloadApply); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=MainNetModeledDurableCompletionFinalizer::default(); let o=evaluate_modeled_durable_completion_finalization_projection(&c.recorded(), &c.expectations, &mut f, &mut ledger); t.check_outcome("A12.mainnet", "mainnet-finalizer-unavailable-no-finalization", &o); t.assert_true("A12.no-record", ledger.is_empty()); }
    { let c=ctx(TrustBundleEnvironment::Mainnet, GovernanceExecutionRuntimeSurface::PeerDrivenDrain, GovernanceExecutionRuntimeSurface::PeerDrivenDrain); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut finalizer=devnet_finalizer(); let o=drive(&c.recorded(), &c.expectations, &mut finalizer, &mut ledger); t.check_outcome("A13.mainnet-peer", "mainnet-peer-driven-apply-refused-no-finalization", &o); t.assert_true("A13.no-invocation", finalizer.invocations()==0); }
    for (id, pipe, sink, report, tag) in [("A14.validator", Pipe::ValidatorSetRotationUnsupportedNoConsume, Sink::ValidatorSetRotationUnsupportedNoConsume, Report::ValidatorSetRotationUnsupportedNoCompletion, "validator-set-rotation-unsupported-no-finalization"), ("A15.policy", Pipe::PolicyChangeUnsupportedNoConsume, Sink::PolicyChangeUnsupportedNoConsume, Report::PolicyChangeUnsupportedNoCompletion, "policy-change-unsupported-no-finalization")] { let c=devnet_ctx(); let input=c.input(P::wired(), R::MutationAuthorized, pipe, sink, report); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=devnet_finalizer(); let o=drive(&input,&c.expectations,&mut f,&mut ledger); t.check_outcome(id, tag, &o); t.assert_true(&format!("{id}.no-invocation"), f.invocations()==0); }
    t.finish(out)
}

fn run_rejection_table(out: &Path) -> (u64, u64) {
    use DurableReplayObservation as R; use GovernanceModeledDurableCompletionFinalizationPolicy as P; use GovernanceModeledEndToEndPipelineOutcome as Pipe; use GovernanceModeledDurableConsumeSinkOutcome as Sink; use GovernanceModeledDurableConsumeCompletionReporterOutcome as Report; let mut t=Table::new("rejection");
    let reporter_cases: [(&str, Report, &str); 13] = [("legacy", Report::LegacyBypassNoCompletionReport, "legacy-bypass-no-finalization"),("rejected-before-sink", Report::RejectedBeforeSinkNoCompletionReport, "rejected-before-reporter-no-finalization"),("sink-did-not-record", Report::SinkDidNotRecordReceiptNoCompletionReport, "reporter-did-not-record-completion-no-finalization"),("reporter-rejected", Report::CompletionReportRejectedBeforeRecord, "reporter-did-not-record-completion-no-finalization"),("record-failed", Report::CompletionReportRecordFailedNoCompletion, "reporter-did-not-record-completion-no-finalization"),("rolled-back", Report::CompletionReportRolledBackNoCompletion, "reporter-did-not-record-completion-no-finalization"),("rollback-failed", Report::CompletionReportRollbackFailedFatalNoCompletion, "reporter-did-not-record-completion-no-finalization"),("ambiguous", Report::CompletionReportAmbiguousFailClosedNoCompletion, "reporter-did-not-record-completion-no-finalization"),("production", Report::ProductionReporterUnavailableNoCompletion, "production-finalizer-unavailable-no-finalization"),("mainnet", Report::MainNetReporterUnavailableNoCompletion, "mainnet-finalizer-unavailable-no-finalization"),("mainnet-peer", Report::MainNetPeerDrivenApplyRefusedNoCompletion, "mainnet-peer-driven-apply-refused-no-finalization"),("validator", Report::ValidatorSetRotationUnsupportedNoCompletion, "validator-set-rotation-unsupported-no-finalization"),("policy", Report::PolicyChangeUnsupportedNoCompletion, "policy-change-unsupported-no-finalization")];
    for (label, report, tag) in reporter_cases { let c=devnet_ctx(); let input=c.input(P::wired(), R::MutationAuthorized, Pipe::ModeledApplierAppliedAndDurableConsumeAuthorized, Sink::ConsumeReceiptRecorded, report); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=devnet_finalizer(); let o=drive(&input,&c.expectations,&mut f,&mut ledger); t.check_outcome(&format!("B.reporter.{label}"), tag, &o); t.assert_true(&format!("B.reporter.{label}.no-record"), ledger.is_empty()); if tag != "durable-completion-finalized" { t.assert_true(&format!("B.reporter.{label}.no-finalization"), o.no_finalization()); } }
    for (label, pipe) in [("evaluator", Pipe::EvaluatorRejectedBeforeReplay{reason:"evaluator rejected".to_string()}),("callsite", Pipe::MutationEngineRejectedBeforeApplier{reason:"binding mismatch".to_string()}),("stale", Pipe::ReplayStaleOrExpiredNoConsume),("consumed", Pipe::ReplayConsumedNoConsume),("superseded", Pipe::ReplaySupersededNoConsume),("backend", Pipe::BackendUnavailableNoConsume),("before-snapshot", Pipe::ModeledApplierRejectedBeforeSnapshot{reason:"read-only validation surface".to_string()}),("before-apply", Pipe::ModeledApplierRejectedBeforeApply{reason:"missing root".to_string()}),("apply-failed", Pipe::ModeledApplierApplyFailedNoConsume),("rollback", Pipe::ModeledApplierRolledBackNoConsume),("rollback-failed", Pipe::ModeledApplierRollbackFailedFatalNoConsume),("ambiguous", Pipe::ModeledApplierAmbiguousFailClosedNoConsume)] { let c=devnet_ctx(); let input=c.input(P::wired(), R::MutationAuthorized, pipe, Sink::PipelineDidNotAuthorizeConsumeNoReceipt, Report::SinkDidNotRecordReceiptNoCompletionReport); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=devnet_finalizer(); let o=drive(&input,&c.expectations,&mut f,&mut ledger); t.check_outcome(&format!("B.pipeline.{label}"), "reporter-did-not-record-completion-no-finalization", &o); t.assert_true(&format!("B.pipeline.{label}.no-invocation"), f.invocations()==0); }
    for (label, sink) in [("did-not", Sink::PipelineDidNotAuthorizeConsumeNoReceipt),("reject", Sink::ConsumeReceiptRejectedBeforeRecord),("record-failure", Sink::ConsumeReceiptRecordFailedNoConsume),("rollback", Sink::ConsumeReceiptRolledBackNoConsume),("rollback-failed", Sink::ConsumeReceiptRollbackFailedFatalNoConsume),("ambiguous", Sink::ConsumeReceiptAmbiguousFailClosedNoConsume)] { let c=devnet_ctx(); let input=c.input(P::wired(), R::MutationAuthorized, Pipe::ModeledApplierAppliedAndDurableConsumeAuthorized, sink, Report::SinkDidNotRecordReceiptNoCompletionReport); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=devnet_finalizer(); let o=drive(&input,&c.expectations,&mut f,&mut ledger); t.check_outcome(&format!("B.sink.{label}"), "reporter-did-not-record-completion-no-finalization", &o); t.assert_true(&format!("B.sink.{label}.no-invocation"), f.invocations()==0); }
    for (label, fault, tag) in [("record-failed", ModeledDurableCompletionFinalizationFault::RecordFailedNoFinalization, "durable-completion-record-failed-no-finalization"),("rollback", ModeledDurableCompletionFinalizationFault::RolledBackNoFinalization, "durable-completion-rolled-back-no-finalization"),("rollback-failed", ModeledDurableCompletionFinalizationFault::RollbackFailedFatal, "durable-completion-rollback-failed-fatal-no-finalization"),("ambiguous", ModeledDurableCompletionFinalizationFault::AmbiguousAfterRecord, "durable-completion-ambiguous-fail-closed-no-finalization")] { let c=devnet_ctx(); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=FixtureModeledDurableCompletionFinalizer::with_fault(TrustBundleEnvironment::Devnet, fault); let o=drive(&c.recorded(),&c.expectations,&mut f,&mut ledger); t.check_outcome(&format!("B.fault.{label}"), tag, &o); t.assert_true(&format!("B.fault.{label}.invoked"), f.invocations()==1); t.assert_true(&format!("B.fault.{label}.empty"), ledger.is_empty()); }
    let binding_cases: [(&str, fn(&mut Ctx)); 5] = [("wrong-environment", (|c: &mut Ctx| { c.env.environment = TrustBundleEnvironment::Testnet; }) as fn(&mut Ctx)), ("wrong-chain", (|c: &mut Ctx| { c.env.chain_id = "qbind-other".to_string(); }) as fn(&mut Ctx)), ("wrong-genesis", (|c: &mut Ctx| { c.env.genesis_hash = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-governance-surface", (|c: &mut Ctx| { c.runtime.governance_surface = GovernanceExecutionRuntimeSurface::Sighup; }) as fn(&mut Ctx)), ("wrong-mutation-surface", (|c: &mut Ctx| { c.runtime.mutation_surface.mutation_surface = GovernanceExecutionRuntimeSurface::StartupP2pTrustBundle; }) as fn(&mut Ctx))];
    for (label, mutate) in binding_cases { let mut c=devnet_ctx(); mutate(&mut c); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=devnet_finalizer(); let o=drive(&c.recorded(),&c.expectations,&mut f,&mut ledger); t.check_outcome(&format!("B.binding.{label}"), "rejected-before-reporter-no-finalization", &o); t.assert_true(&format!("B.binding.{label}.no-invocation"), f.invocations()==0); }
    let finalization_cases: [(&str, fn(&mut Ctx)); 11] = [("wrong-finalization-digest", (|c: &mut Ctx| { c.finalization.finalization_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-report-digest", (|c: &mut Ctx| { c.finalization.report_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-receipt-digest", (|c: &mut Ctx| { c.finalization.receipt_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-sink-decision-digest", (|c: &mut Ctx| { c.finalization.sink_decision_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-reporter-decision-digest", (|c: &mut Ctx| { c.finalization.reporter_decision_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-pipeline-decision-digest", (|c: &mut Ctx| { c.finalization.pipeline_decision_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-proposal", (|c: &mut Ctx| { c.finalization.proposal_id = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-decision", (|c: &mut Ctx| { c.finalization.decision_id = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-candidate", (|c: &mut Ctx| { c.finalization.candidate_digest = "wrong".to_string(); }) as fn(&mut Ctx)), ("wrong-sequence", (|c: &mut Ctx| { c.finalization.authority_domain_sequence = 99; }) as fn(&mut Ctx)), ("malformed", (|c: &mut Ctx| { c.finalization.finalization_id = String::new(); }) as fn(&mut Ctx))];
    for (label, mutate) in finalization_cases { let mut c=devnet_ctx(); mutate(&mut c); let mut ledger=ModeledDurableCompletionFinalizationLedger::new(); let mut f=devnet_finalizer(); let o=drive(&c.recorded(),&c.expectations,&mut f,&mut ledger); t.check_outcome(&format!("B.finalization.{label}"), "durable-completion-rejected-before-record", &o); t.assert_true(&format!("B.finalization.{label}.invoked"), f.invocations()==1); t.assert_true(&format!("B.finalization.{label}.empty"), ledger.is_empty()); }
    t.assert_true("B.local-operator-cannot", modeled_finalization_local_operator_cannot_satisfy_mainnet_authority()); t.assert_true("B.peer-majority-cannot", modeled_finalization_peer_majority_cannot_satisfy_mainnet_authority());
    t.finish(out)
}

